import { Fragment, useEffect, useMemo, useState } from "react";
import { Link, useParams } from "react-router-dom";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { api, getApiErrorMessage } from "@/services/api";

type StaffClient = {
  id: string;
  email: string;
  first_name: string;
  last_name: string;
  full_name: string;
  phone: string;
  company: string;
  is_verified: boolean;
  created_at: string;
  demandes_count: number;
};

export default function FournisseurClients() {
  const { id } = useParams();
  const [expanded, setExpanded] = useState<string | null>(null);
  const [query, setQuery] = useState("");
  const [clients, setClients] = useState<StaffClient[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [detail, setDetail] = useState<StaffClient | null>(null);
  const [detailLoading, setDetailLoading] = useState(false);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      setLoading(true);
      setError(null);
      try {
        const { data } = await api.get<StaffClient[]>("/auth/staff/clients/");
        if (!cancelled) setClients(data);
      } catch (e) {
        if (!cancelled) setError(getApiErrorMessage(e, "Impossible de charger les clients."));
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, []);

  useEffect(() => {
    if (!id) {
      setDetail(null);
      return;
    }
    let cancelled = false;
    (async () => {
      setDetailLoading(true);
      setError(null);
      try {
        const { data } = await api.get<StaffClient>(`/auth/staff/clients/${id}/`);
        if (!cancelled) setDetail(data);
      } catch (e) {
        if (!cancelled) {
          setDetail(null);
          setError(getApiErrorMessage(e, "Client introuvable."));
        }
      } finally {
        if (!cancelled) setDetailLoading(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [id]);

  if (id) {
    if (detailLoading) return <p className="text-sm text-slate-500">Chargement...</p>;
    if (!detail) return <p className="text-sm text-slate-500">{error ?? "Client introuvable."}</p>;
    return (
      <div className="grid gap-4 xl:grid-cols-12">
        <Card className="xl:col-span-4">
          <CardHeader>
            <CardTitle>Fiche client</CardTitle>
          </CardHeader>
          <CardContent className="space-y-2 text-sm">
            <p className="text-lg font-semibold">{detail.full_name}</p>
            <p>{detail.email}</p>
            {detail.phone && <p>{detail.phone}</p>}
            {detail.company && <p className="text-slate-600">{detail.company}</p>}
            <Badge className="bg-emerald-100 text-emerald-800">Compte verifie</Badge>
            <p className="text-xs text-slate-500">
              Inscrit le {new Date(detail.created_at).toLocaleDateString("fr-FR")}
            </p>
            <p className="text-xs text-slate-500">Demandes: {detail.demandes_count}</p>
          </CardContent>
        </Card>

        <Card className="xl:col-span-8">
          <CardHeader>
            <CardTitle>Activite</CardTitle>
          </CardHeader>
          <CardContent className="text-sm text-slate-600">
            <p>L&apos;historique detaille (demandes, documents) sera lie a ce client lorsqu&apos;il aura des dossiers sur la plateforme.</p>
          </CardContent>
        </Card>
      </div>
    );
  }

  const filtered = useMemo(
    () =>
      clients.filter((item) => {
        const q = query.toLowerCase();
        return (
          item.full_name.toLowerCase().includes(q) ||
          item.email.toLowerCase().includes(q) ||
          (item.company && item.company.toLowerCase().includes(q))
        );
      }),
    [clients, query]
  );

  return (
    <div className="space-y-4">
      <Card>
        <CardContent className="flex flex-wrap items-center gap-3 p-4">
          <h2 className="text-lg font-semibold">Clients</h2>
          <Input
            className="max-w-md"
            placeholder="Rechercher nom, email, societe..."
            value={query}
            onChange={(event) => setQuery(event.target.value)}
          />
          <p className="text-xs text-slate-500">Clients avec compte email verifie</p>
        </CardContent>
      </Card>

      {error && !id && (
        <p className="rounded-md bg-red-50 px-3 py-2 text-sm text-red-700">{error}</p>
      )}

      <Card>
        <CardContent className="overflow-x-auto p-0">
          {loading ? (
            <p className="p-8 text-center text-sm text-slate-500">Chargement des clients...</p>
          ) : (
            <table className="min-w-full text-sm">
              <thead className="bg-slate-50 text-left text-slate-500">
                <tr>
                  <th className="px-4 py-3">Client</th>
                  <th className="px-4 py-3">Email</th>
                  <th className="px-4 py-3">Telephone</th>
                  <th className="px-4 py-3">Societe</th>
                  <th className="px-4 py-3">Demandes</th>
                  <th className="px-4 py-3">Inscription</th>
                  <th className="px-4 py-3">Actions</th>
                </tr>
              </thead>
              <tbody>
                {filtered.length === 0 ? (
                  <tr>
                    <td className="px-4 py-8 text-center text-slate-500" colSpan={7}>
                      Aucun client pour le moment.
                    </td>
                  </tr>
                ) : (
                  filtered.map((client) => (
                    <Fragment key={client.id}>
                      <tr className="border-t border-slate-100">
                        <td className="px-4 py-3 font-medium">{client.full_name}</td>
                        <td className="px-4 py-3">{client.email}</td>
                        <td className="px-4 py-3">{client.phone || "—"}</td>
                        <td className="px-4 py-3">{client.company || "—"}</td>
                        <td className="px-4 py-3">{client.demandes_count}</td>
                        <td className="px-4 py-3">
                          {new Date(client.created_at).toLocaleDateString("fr-FR")}
                        </td>
                        <td className="px-4 py-3">
                          <div className="flex gap-2">
                            <Button
                              variant="outline"
                              size="sm"
                              onClick={() => setExpanded((prev) => (prev === client.id ? null : client.id))}
                            >
                              {expanded === client.id ? "Replier" : "Apercu"}
                            </Button>
                            <Button variant="outline" size="sm" asChild>
                              <Link to={`/fournisseur/clients/${client.id}`}>Profil</Link>
                            </Button>
                          </div>
                        </td>
                      </tr>
                      {expanded === client.id && (
                        <tr className="border-t border-slate-100 bg-slate-50/60">
                          <td className="px-4 py-3" colSpan={7}>
                            <p className="text-sm text-slate-600">
                              ID: {client.id} — {client.demandes_count} demande(s) enregistree(s).
                            </p>
                          </td>
                        </tr>
                      )}
                    </Fragment>
                  ))
                )}
              </tbody>
            </table>
          )}
        </CardContent>
      </Card>
    </div>
  );
}
