import { AlertTriangle, CalendarDays, CheckCircle2, CircleDollarSign, ClipboardList, Users, Eye, UserPlus2, Pencil } from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

const kpis = [
  { icon: ClipboardList, label: "Demandes actives", value: "0" },
  { icon: AlertTriangle, label: "Urgentes ce jour", value: "0" },
  { icon: CheckCircle2, label: "Traitees ce mois", value: "0" },
  { icon: CalendarDays, label: "RDV aujourd'hui", value: "0" },
  { icon: Users, label: "Clients actifs", value: "0" },
  { icon: CircleDollarSign, label: "Revenus ce mois", value: "0 MAD" },
];

const demandes: Array<{ id: string; client: string; domaine: string; urgence: string; statut: string; date: string; assigne: string }> = [];

const rendezVous: Array<{ time: string; client: string; domain: string }> = [];

const donutData: Array<{ label: string; value: number; color: string }> = [];

const monthly: Array<{ month: string; submitted: number; treated: number }> = [];

const satisfaction: Array<{ stars: string; pct: number }> = [];

function donutGradient() {
  if (donutData.length === 0) {
    return "conic-gradient(#e2e8f0 0% 100%)";
  }
  let start = 0;
  const segments = donutData.map((segment) => {
    const end = start + segment.value;
    const value = `${segment.color} ${start}% ${end}%`;
    start = end;
    return value;
  });
  return `conic-gradient(${segments.join(", ")})`;
}

export default function FournisseurDashboard() {
  return (
    <div className="space-y-6">
      <section className="grid gap-4 md:grid-cols-3">
        {kpis.map((kpi) => (
          <Card key={kpi.label}>
            <CardContent className="p-5">
              <div className="mb-2 flex items-center justify-between">
                <kpi.icon className="h-5 w-5 text-cyan" />
              </div>
              <p className="text-sm text-slate-500">{kpi.label}</p>
              <p className="mt-1 text-2xl font-semibold text-slate-900">{kpi.value}</p>
            </CardContent>
          </Card>
        ))}
      </section>

      <section className="grid gap-4 xl:grid-cols-12">
        <Card className="xl:col-span-8">
          <CardHeader>
            <CardTitle>Demandes recentes</CardTitle>
          </CardHeader>
          <CardContent className="p-0">
            <div className="overflow-x-auto">
              <table className="min-w-full text-sm">
                <thead className="bg-slate-50 text-left text-slate-500">
                  <tr>
                    <th className="px-4 py-3">Client</th>
                    <th className="px-4 py-3">Domaine</th>
                    <th className="px-4 py-3">Urgence</th>
                    <th className="px-4 py-3">Statut</th>
                    <th className="px-4 py-3">Date</th>
                    <th className="px-4 py-3">Assigne a</th>
                    <th className="px-4 py-3">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {demandes.map((demande) => (
                    <tr
                      key={demande.id}
                      className={cn(
                        "border-t border-slate-100",
                        demande.urgence === "Critique" && "border-l-4 border-l-red-500",
                        demande.urgence === "Urgente" && "border-l-4 border-l-amber-500"
                      )}
                    >
                      <td className="px-4 py-3 font-medium text-slate-700">{demande.client}</td>
                      <td className="px-4 py-3">{demande.domaine}</td>
                      <td className="px-4 py-3">
                        <Badge className={cn("border", demande.urgence === "Critique" ? "bg-red-100 text-red-700 border-red-200" : demande.urgence === "Urgente" ? "bg-amber-100 text-amber-700 border-amber-200" : "bg-slate-100 text-slate-700 border-slate-200")}>
                          {demande.urgence}
                        </Badge>
                      </td>
                      <td className="px-4 py-3">{demande.statut}</td>
                      <td className="px-4 py-3">{demande.date}</td>
                      <td className="px-4 py-3">{demande.assigne}</td>
                      <td className="px-4 py-3">
                        <div className="flex flex-wrap gap-2">
                          <Button size="sm" variant="outline"><Eye className="mr-1 h-3.5 w-3.5" /> Voir</Button>
                          <Button size="sm" variant="outline"><UserPlus2 className="mr-1 h-3.5 w-3.5" /> Assigner</Button>
                          <Button size="sm" variant="outline"><Pencil className="mr-1 h-3.5 w-3.5" /> Statut</Button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </CardContent>
        </Card>

        <div className="space-y-4 xl:col-span-4">
          <Card>
            <CardHeader>
              <CardTitle>Rendez-vous du jour</CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">
              {rendezVous.map((meeting) => (
                <div key={`${meeting.time}-${meeting.client}`} className="flex items-center justify-between rounded-lg border border-slate-200 p-3">
                  <div>
                    <p className="text-sm font-semibold">{meeting.time} - {meeting.client}</p>
                    <p className="text-xs text-slate-500">{meeting.domain}</p>
                  </div>
                  <Button size="sm" className="bg-cyan text-white hover:bg-cyan/90">Rejoindre</Button>
                </div>
              ))}
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Alertes</CardTitle>
            </CardHeader>
            <CardContent className="space-y-2 text-sm">
              <p className="rounded-md bg-red-50 px-3 py-2 text-red-700">Demande en retard (&gt; 48h sans reponse)</p>
              <p className="rounded-md bg-amber-50 px-3 py-2 text-amber-700">Consultations sans compte-rendu</p>
              <p className="rounded-md bg-cyan-50 px-3 py-2 text-cyan-700">Factures impayees (&gt; 30j)</p>
            </CardContent>
          </Card>
        </div>
      </section>

      <section className="grid gap-4 xl:grid-cols-3">
        <Card>
          <CardHeader>
            <CardTitle>Demandes par domaine</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="mx-auto h-44 w-44 rounded-full" style={{ background: donutGradient() }} />
            <div className="mt-4 space-y-2 text-sm">
              {donutData.map((item) => (
                <p key={item.label} className="flex items-center gap-2">
                  <span className="h-2.5 w-2.5 rounded-full" style={{ backgroundColor: item.color }} />
                  {item.label} - {item.value}%
                </p>
              ))}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Evolution mensuelle</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {monthly.map((item) => (
                <div key={item.month}>
                  <div className="mb-1 flex items-center justify-between text-xs text-slate-500">
                    <span>{item.month}</span>
                    <span>{item.submitted}/{item.treated}</span>
                  </div>
                  <div className="space-y-1">
                    <div className="h-2 rounded-full bg-slate-100">
                      <div className="h-full rounded-full bg-slate-300" style={{ width: `${Math.min(item.submitted * 3, 100)}%` }} />
                    </div>
                    <div className="h-2 rounded-full bg-slate-100">
                      <div className="h-full rounded-full bg-cyan" style={{ width: `${Math.min(item.treated * 3, 100)}%` }} />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Satisfaction clients</CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            {satisfaction.map((row) => (
              <div key={row.stars} className="grid grid-cols-[36px_1fr_44px] items-center gap-2 text-sm">
                <span>{row.stars}</span>
                <div className="h-2 rounded-full bg-slate-100">
                  <div className="h-full rounded-full bg-amber-400" style={{ width: `${row.pct}%` }} />
                </div>
                <span className="text-right text-slate-600">{row.pct}%</span>
              </div>
            ))}
          </CardContent>
        </Card>
      </section>
    </div>
  );
}
