import { useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { useDashboard } from "@/pages/client/DashboardContext";
import type { Consultation } from "@/types/client";

function getMonthGrid(base: Date) {
  const first = new Date(base.getFullYear(), base.getMonth(), 1);
  const offset = (first.getDay() + 6) % 7;
  const start = new Date(base.getFullYear(), base.getMonth(), 1 - offset);
  return Array.from({ length: 42 }).map((_, i) => {
    const d = new Date(start);
    d.setDate(start.getDate() + i);
    return d;
  });
}

export default function ClientMeetings() {
  const { consultations } = useDashboard();
  const [monthDate, setMonthDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().slice(0, 10));
  const [meetings, setMeetings] = useState<Consultation[]>([]);
  const monthGrid = useMemo(() => getMonthGrid(monthDate), [monthDate]);
  const from = new Date(monthDate.getFullYear(), monthDate.getMonth(), 1).toISOString().slice(0, 10);
  const to = new Date(monthDate.getFullYear(), monthDate.getMonth() + 1, 0).toISOString().slice(0, 10);

  useEffect(() => {
    const loadMeetings = async () => {
      try {
        const response = await fetch(`/api/meetings?clientId=demo-client&from=${from}&to=${to}`);
        if (!response.ok) throw new Error("request_failed");
        const data = (await response.json()) as Consultation[];
        setMeetings(data);
      } catch {
        setMeetings(consultations.filter((c) => c.status === "planifiee" || c.status === "en_cours"));
      }
    };
    loadMeetings();
  }, [consultations, from, to]);

  const byDate = useMemo(() => {
    const map = new Map<string, Consultation[]>();
    meetings.forEach((meeting) => {
      const day = meeting.scheduledAt.slice(0, 10);
      map.set(day, [...(map.get(day) || []), meeting]);
    });
    return map;
  }, [meetings]);

  const selectedMeetings = useMemo(() => byDate.get(selectedDate) ?? meetings, [byDate, selectedDate, meetings]);

  const cancelMeeting = async (id: string) => {
    await fetch(`/api/meetings/${id}/cancel`, { method: "PATCH" }).catch(() => undefined);
    setMeetings((prev) => prev.map((meeting) => (meeting.id === id ? { ...meeting, status: "annulee" } : meeting)));
  };

  const rescheduleMeeting = async (id: string) => {
    await fetch(`/api/meetings/${id}/reschedule`, { method: "PATCH" }).catch(() => undefined);
    setMeetings((prev) => prev.map((meeting) => (meeting.id === id ? { ...meeting, status: "planifiee" } : meeting)));
  };

  const today = new Date().toISOString().slice(0, 10);

  return (
    <Card>
      <CardHeader>
        <CardTitle className="text-xl">Mes rendez-vous</CardTitle>
      </CardHeader>
      <CardContent className="grid gap-6 lg:grid-cols-[1.1fr_1fr]">
        <div className="rounded-xl border border-slate-200 p-4 dark:border-slate-700">
          <div className="mb-4 flex items-center justify-between">
            <Button size="sm" variant="outline" onClick={() => setMonthDate((prev) => new Date(prev.getFullYear(), prev.getMonth() - 1, 1))}>
              Prev
            </Button>
            <p className="font-semibold capitalize">{monthDate.toLocaleDateString("fr-FR", { month: "long", year: "numeric" })}</p>
            <Button size="sm" variant="outline" onClick={() => setMonthDate((prev) => new Date(prev.getFullYear(), prev.getMonth() + 1, 1))}>
              Next
            </Button>
          </div>
          <div className="mb-2 grid grid-cols-7 gap-1 text-center text-xs uppercase text-slate-500">
            {["Lun", "Mar", "Mer", "Jeu", "Ven", "Sam", "Dim"].map((day) => (
              <span key={day}>{day}</span>
            ))}
          </div>
          <div className="grid grid-cols-7 gap-1">
            {monthGrid.map((day) => {
              const iso = day.toISOString().slice(0, 10);
              const inMonth = day.getMonth() === monthDate.getMonth();
              const hasMeetings = (byDate.get(iso) || []).length > 0;
              return (
                <button
                  key={iso}
                  type="button"
                  onClick={() => setSelectedDate(iso)}
                  className={`relative h-10 rounded border text-sm ${
                    iso === selectedDate ? "border-cyan bg-cyan/10" : iso === today ? "border-cyan" : "border-slate-200 dark:border-slate-700"
                  } ${inMonth ? "text-slate-800 dark:text-slate-100" : "text-slate-400"}`}
                >
                  {day.getDate()}
                  {hasMeetings && <span className="absolute bottom-1 left-1/2 h-1.5 w-1.5 -translate-x-1/2 rounded-full bg-cyan" />}
                </button>
              );
            })}
          </div>
          <div className="mt-4">
            <Link to="/consultation" className="text-sm font-medium text-cyan hover:underline">
              Planifier un nouveau rendez-vous →
            </Link>
          </div>
        </div>

        <div className="space-y-3">
          <p className="font-semibold text-slate-800 dark:text-slate-100">{selectedDate ? `Rendez-vous du ${new Date(selectedDate).toLocaleDateString("fr-FR")}` : "Tous les rendez-vous"}</p>
          {selectedMeetings.map((meeting) => (
            <div key={meeting.id} className="rounded-xl border border-slate-200 p-4 dark:border-slate-700">
              <div className="mb-3 flex items-center justify-between">
                <Badge className="bg-slate-100 text-slate-700">
                  {new Date(meeting.scheduledAt).toLocaleTimeString("fr-FR", { hour: "2-digit", minute: "2-digit" })} -{" "}
                  {new Date(new Date(meeting.scheduledAt).getTime() + meeting.duration * 60000).toLocaleTimeString("fr-FR", { hour: "2-digit", minute: "2-digit" })}
                </Badge>
                <Badge className={meeting.status === "en_cours" ? "bg-emerald-100 text-emerald-700" : meeting.status === "planifiee" ? "bg-amber-100 text-amber-700" : "bg-red-100 text-red-700"}>
                  {meeting.status === "en_cours" ? "Confirme ✅" : meeting.status === "planifiee" ? "En attente ⏳" : "Annule ❌"}
                </Badge>
              </div>
              <p className="font-semibold">
                Me. {meeting.expert.firstName} {meeting.expert.lastName}
              </p>
              <Badge variant="outline" className="mt-1">
                {meeting.expert.specialization[0].replace("_", " ")}
              </Badge>
              <div className="mt-4 flex flex-wrap gap-2">
                <Button size="sm" onClick={() => meeting.meetingUrl && window.open(meeting.meetingUrl, "_blank", "noopener,noreferrer")}>
                  Rejoindre
                </Button>
                <Button size="sm" variant="outline">
                  Details
                </Button>
                <Button size="sm" variant="outline" onClick={() => rescheduleMeeting(meeting.id)}>
                  Reprogrammer
                </Button>
                <Button size="sm" variant="outline" className="border-red-200 text-red-600 hover:bg-red-50" onClick={() => cancelMeeting(meeting.id)}>
                  Annuler
                </Button>
              </div>
            </div>
          ))}
        </div>
      </CardContent>
    </Card>
  );
}
