import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";

const invoices: Array<{ id: string; client: string; service: string; amount: string; status: string; due: string }> = [];

const revenue: Array<{ month: string; value: number }> = [];

export default function FournisseurFacturation() {
  const [tab, setTab] = useState<"factures" | "revenus">("factures");
  const [showModal, setShowModal] = useState(false);
  const [invoiceForm, setInvoiceForm] = useState({
    client: "",
    service: "",
    amount: "",
    currency: "MAD",
    dueDate: "",
    sendClient: true,
  });

  return (
    <div className="space-y-4">
      <Card>
        <CardContent className="flex items-center gap-2 p-4">
          <Button variant={tab === "factures" ? "default" : "outline"} className={tab === "factures" ? "bg-cyan text-white hover:bg-cyan/90" : ""} onClick={() => setTab("factures")}>Factures</Button>
          <Button variant={tab === "revenus" ? "default" : "outline"} className={tab === "revenus" ? "bg-cyan text-white hover:bg-cyan/90" : ""} onClick={() => setTab("revenus")}>Revenus</Button>
        </CardContent>
      </Card>

      {tab === "factures" ? (
        <Card>
          <CardHeader className="flex-row items-center justify-between">
            <CardTitle>Factures</CardTitle>
            <Button className="bg-cyan text-white hover:bg-cyan/90" onClick={() => setShowModal(true)}>Creer une facture</Button>
          </CardHeader>
          <CardContent className="overflow-x-auto p-0">
            <table className="min-w-full text-sm">
              <thead className="bg-slate-50 text-left text-slate-500">
                <tr>
                  <th className="px-4 py-3">Client</th>
                  <th className="px-4 py-3">Service</th>
                  <th className="px-4 py-3">Montant</th>
                  <th className="px-4 py-3">Statut</th>
                  <th className="px-4 py-3">Echeance</th>
                  <th className="px-4 py-3">Actions</th>
                </tr>
              </thead>
              <tbody>
                {invoices.map((invoice) => (
                  <tr key={invoice.id} className="border-t border-slate-100">
                    <td className="px-4 py-3">{invoice.client}</td>
                    <td className="px-4 py-3">{invoice.service}</td>
                    <td className="px-4 py-3">{invoice.amount}</td>
                    <td className="px-4 py-3">{invoice.status}</td>
                    <td className="px-4 py-3">{invoice.due}</td>
                    <td className="px-4 py-3">
                      <div className="flex gap-2">
                        <Button size="sm" variant="outline">Voir PDF</Button>
                        <Button size="sm" variant="outline">Relancer</Button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </CardContent>
        </Card>
      ) : (
        <div className="grid gap-4 xl:grid-cols-12">
          <Card className="xl:col-span-8">
            <CardHeader><CardTitle>Revenus mensuels</CardTitle></CardHeader>
            <CardContent className="space-y-3">
              {revenue.map((row) => (
                <div key={row.month}>
                  <div className="mb-1 flex justify-between text-xs text-slate-500">
                    <span>{row.month}</span>
                    <span>{row.value}k MAD</span>
                  </div>
                  <div className="h-3 rounded-full bg-slate-100">
                    <div className="h-full rounded-full bg-cyan" style={{ width: `${row.value * 2.5}%` }} />
                  </div>
                </div>
              ))}
            </CardContent>
          </Card>
          <Card className="xl:col-span-4">
            <CardHeader><CardTitle>Repartition services</CardTitle></CardHeader>
            <CardContent className="space-y-2 text-sm">
              <p>Affaires: 38%</p>
              <p>RGPD: 24%</p>
              <p>IA: 20%</p>
              <p>PI: 10%</p>
              <p>Numerique: 8%</p>
              <Button className="mt-3 w-full" variant="outline">Export CSV</Button>
            </CardContent>
          </Card>
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 p-4">
          <Card className="w-full max-w-2xl">
            <CardHeader><CardTitle>Creer une facture</CardTitle></CardHeader>
            <CardContent className="space-y-3">
              <Input placeholder="Client (autocomplete)" value={invoiceForm.client} onChange={(event) => setInvoiceForm((prev) => ({ ...prev, client: event.target.value }))} />
              <Textarea placeholder="Description service" value={invoiceForm.service} onChange={(event) => setInvoiceForm((prev) => ({ ...prev, service: event.target.value }))} />
              <div className="grid gap-3 md:grid-cols-3">
                <Input placeholder="Montant" value={invoiceForm.amount} onChange={(event) => setInvoiceForm((prev) => ({ ...prev, amount: event.target.value }))} />
                <select className="h-10 rounded-md border border-slate-200 px-3 text-sm" value={invoiceForm.currency} onChange={(event) => setInvoiceForm((prev) => ({ ...prev, currency: event.target.value }))}>
                  <option value="MAD">MAD</option>
                  <option value="EUR">EUR</option>
                </select>
                <Input type="date" value={invoiceForm.dueDate} onChange={(event) => setInvoiceForm((prev) => ({ ...prev, dueDate: event.target.value }))} />
              </div>
              <div className="rounded-md border border-slate-200 bg-slate-50 p-3 text-sm">Apercu PDF auto-genere: {invoiceForm.client || "Client"} - {invoiceForm.amount || "0"} {invoiceForm.currency}</div>
              <label className="flex items-center gap-2 text-sm">
                <input type="checkbox" checked={invoiceForm.sendClient} onChange={(event) => setInvoiceForm((prev) => ({ ...prev, sendClient: event.target.checked }))} />
                Envoyer au client
              </label>
              <div className="flex justify-end gap-2">
                <Button variant="outline" onClick={() => setShowModal(false)}>Annuler</Button>
                <Button
                  className="bg-cyan text-white hover:bg-cyan/90"
                  onClick={async () => {
                    await fetch("/api/invoices", {
                      method: "POST",
                      headers: { "Content-Type": "application/json" },
                      body: JSON.stringify(invoiceForm),
                    }).catch(() => undefined);
                    setShowModal(false);
                  }}
                >
                  Enregistrer
                </Button>
              </div>
            </CardContent>
          </Card>
        </div>
      )}
    </div>
  );
}
