import { useMemo, useState } from "react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { cn } from "@/lib/utils";

type InvoiceStatus = "payee" | "en_attente" | "en_retard";
type PaymentMethod = "carte" | "virement" | "cmi";

interface Invoice {
  id: string;
  service: string;
  amount: number;
  status: InvoiceStatus;
  date: string;
  pdfUrl: string;
}

const INITIAL_INVOICES: Invoice[] = [
  { id: "FAC-2026-001", service: "Audit RGPD", amount: 2400, status: "payee", date: "2026-03-18", pdfUrl: "#" },
  { id: "FAC-2026-002", service: "Revision contrat", amount: 1200, status: "en_attente", date: "2026-03-26", pdfUrl: "#" },
  { id: "FAC-2026-003", service: "Consultation droit IA", amount: 1800, status: "en_retard", date: "2026-03-12", pdfUrl: "#" },
];

const STATUS_LABEL: Record<InvoiceStatus, string> = {
  payee: "Payee",
  en_attente: "En attente",
  en_retard: "En retard",
};

const STATUS_CLASS: Record<InvoiceStatus, string> = {
  payee: "bg-green-100 text-green-700 border-green-200",
  en_attente: "bg-amber-100 text-amber-700 border-amber-200",
  en_retard: "bg-red-100 text-red-700 border-red-200",
};

function formatMad(value: number) {
  return `${value.toLocaleString("fr-FR")} MAD`;
}

export default function ClientFactures() {
  const [invoices] = useState(INITIAL_INVOICES);
  const [activeInvoice, setActiveInvoice] = useState<Invoice | null>(null);
  const [method, setMethod] = useState<PaymentMethod>("carte");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [paymentError, setPaymentError] = useState("");

  const summary = useMemo(() => {
    return invoices.reduce(
      (acc, invoice) => {
        if (invoice.status === "payee") acc.totalRegle += invoice.amount;
        else acc.totalEnAttente += invoice.amount;
        acc.nbFactures += 1;
        return acc;
      },
      { totalRegle: 0, totalEnAttente: 0, nbFactures: 0 }
    );
  }, [invoices]);

  const startPayment = (invoice: Invoice) => {
    setActiveInvoice(invoice);
    setMethod("carte");
    setPaymentError("");
  };

  const submitPaymentIntent = async () => {
    if (!activeInvoice) return;
    setIsSubmitting(true);
    setPaymentError("");
    try {
      const response = await fetch("/api/payments/intent", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ invoiceId: activeInvoice.id, method }),
      });
      if (!response.ok) throw new Error("intent_failed");

      // In real flow backend returns gateway URL. Fallback uses local payment path.
      const data = (await response.json().catch(() => ({}))) as { redirectUrl?: string };
      window.location.href = data.redirectUrl ?? `/payment?invoice=${activeInvoice.id}`;
    } catch {
      setPaymentError("Impossible d'initialiser le paiement. Veuillez reessayer.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-4">
      <Card>
        <CardHeader>
          <CardTitle className="text-xl">Mes factures</CardTitle>
        </CardHeader>
      </Card>

      <section className="grid gap-4 md:grid-cols-3">
        <Card>
          <CardContent className="p-5">
            <p className="text-sm text-slate-500">Total regle</p>
            <p className="mt-1 text-2xl font-semibold">{formatMad(summary.totalRegle)}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-5">
            <p className="text-sm text-slate-500">En attente</p>
            <p className="mt-1 text-2xl font-semibold">{formatMad(summary.totalEnAttente)}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-5">
            <p className="text-sm text-slate-500">Nb factures</p>
            <p className="mt-1 text-2xl font-semibold">{summary.nbFactures}</p>
          </CardContent>
        </Card>
      </section>

      <Card>
        <CardContent className="overflow-x-auto p-0">
          <table className="min-w-full text-sm">
            <thead className="bg-slate-50 text-left text-slate-500">
              <tr>
                <th className="px-4 py-3">N Facture</th>
                <th className="px-4 py-3">Service</th>
                <th className="px-4 py-3">Montant</th>
                <th className="px-4 py-3">Statut</th>
                <th className="px-4 py-3">Date</th>
                <th className="px-4 py-3">Actions</th>
              </tr>
            </thead>
            <tbody>
              {invoices.map((invoice) => (
                <tr key={invoice.id} className="border-t border-slate-100 dark:border-slate-800">
                  <td className="px-4 py-3 font-medium">{invoice.id}</td>
                  <td className="px-4 py-3">{invoice.service}</td>
                  <td className="px-4 py-3">{formatMad(invoice.amount)}</td>
                  <td className="px-4 py-3">
                    <Badge className={cn("border", STATUS_CLASS[invoice.status])}>{STATUS_LABEL[invoice.status]}</Badge>
                  </td>
                  <td className="px-4 py-3">{new Date(invoice.date).toLocaleDateString("fr-FR")}</td>
                  <td className="px-4 py-3">
                    <div className="flex flex-wrap gap-2">
                      <a href={invoice.pdfUrl} download={`${invoice.id}.pdf`}>
                        <Button size="sm" variant="outline">Telecharger PDF</Button>
                      </a>
                      {invoice.status === "en_attente" && (
                        <Button size="sm" onClick={() => startPayment(invoice)}>Payer maintenant</Button>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </CardContent>
      </Card>

      {activeInvoice && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 p-4">
          <Card className="w-full max-w-xl">
            <CardHeader className="flex flex-row items-center justify-between">
              <CardTitle>Paiement securise</CardTitle>
              <Button variant="ghost" onClick={() => setActiveInvoice(null)}>
                Fermer
              </Button>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="rounded-lg border border-slate-200 p-4 text-sm dark:border-slate-700">
                <p className="font-medium">{activeInvoice.id}</p>
                <p className="text-slate-600 dark:text-slate-300">{activeInvoice.service}</p>
                <p className="mt-2 text-lg font-semibold">{formatMad(activeInvoice.amount)}</p>
              </div>

              <div className="space-y-2">
                <p className="text-sm font-medium">Methode de paiement</p>
                <div className="grid gap-2 sm:grid-cols-3">
                  <button
                    type="button"
                    onClick={() => setMethod("carte")}
                    className={cn("rounded-md border px-3 py-2 text-sm", method === "carte" ? "border-cyan bg-cyan/10 text-cyan" : "border-slate-200 dark:border-slate-700")}
                  >
                    Carte bancaire
                  </button>
                  <button
                    type="button"
                    onClick={() => setMethod("virement")}
                    className={cn("rounded-md border px-3 py-2 text-sm", method === "virement" ? "border-cyan bg-cyan/10 text-cyan" : "border-slate-200 dark:border-slate-700")}
                  >
                    Virement
                  </button>
                  <button
                    type="button"
                    onClick={() => setMethod("cmi")}
                    className={cn("rounded-md border px-3 py-2 text-sm", method === "cmi" ? "border-cyan bg-cyan/10 text-cyan" : "border-slate-200 dark:border-slate-700")}
                  >
                    CMI
                  </button>
                </div>
              </div>

              <div className="rounded-md border border-emerald-200 bg-emerald-50 px-3 py-2 text-sm text-emerald-700">
                Paiement securise
              </div>

              {paymentError && <p className="text-sm text-red-600">{paymentError}</p>}

              <div className="flex justify-end">
                <Button onClick={submitPaymentIntent} disabled={isSubmitting}>
                  {isSubmitting ? "Redirection..." : "Continuer vers la passerelle"}
                </Button>
              </div>
            </CardContent>
          </Card>
        </div>
      )}
    </div>
  );
}
