import { Navigate, Outlet, useLocation } from "react-router-dom";
import { useAuth } from "@/context/AuthContext";
import type { UserRole } from "@/types/auth";

interface ProtectedRouteProps {
  /** If set, only these roles may access child routes. Others are redirected to their home dashboard. */
  allowedRoles?: UserRole[];
}

function homePathForRole(role: UserRole): string {
  if (role === "provider") return "/fournisseur/dashboard";
  if (role === "admin") return "/fournisseur/dashboard";
  return "/espace-client/dashboard";
}

export default function ProtectedRoute({ allowedRoles }: ProtectedRouteProps) {
  const { isAuthenticated, isLoading, user } = useAuth();
  const location = useLocation();

  if (isLoading) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-slate-50 text-slate-700">
        Chargement...
      </div>
    );
  }

  if (!isAuthenticated) {
    const isEquipePage = location.pathname.includes("/equipe");
    const loginUrl = location.pathname.startsWith("/fournisseur")
      ? isEquipePage
        ? "/client-space/login?espace=admin"
        : "/client-space/login?espace=expert"
      : "/client-space/login";
    return <Navigate to={loginUrl} state={{ from: location }} replace />;
  }

  if (location.pathname.startsWith("/provider-space") && user?.role !== "provider") {
    return <Navigate to="/client-space/login?espace=expert" replace />;
  }

  if (allowedRoles && allowedRoles.length > 0 && user && !allowedRoles.includes(user.role)) {
    return <Navigate to={homePathForRole(user.role)} replace />;
  }

  return <Outlet />;
}
