import type { RegisterData, User, UserRole } from "@/types/auth";
import { api, setAuthToken } from "./api";

type BackendUser = {
  id: string;
  email: string;
  first_name: string;
  last_name: string;
  role: "client" | "fournisseur" | "admin";
  company?: string;
  avatar?: string;
};

type LoginResponse = {
  access: string;
  refresh: string;
  user: BackendUser;
};

type RegisterResponse = {
  user: BackendUser;
  detail?: string;
};

function mapRole(role: BackendUser["role"]): UserRole {
  if (role === "fournisseur") return "provider";
  return role;
}

function mapUser(user: BackendUser): User {
  return {
    id: user.id,
    firstName: user.first_name,
    lastName: user.last_name,
    email: user.email,
    role: mapRole(user.role),
    accountType: "particulier",
    company: user.company,
    avatar: user.avatar,
  };
}

export async function login(email: string, password: string): Promise<{ user: User; token: string; refresh: string }> {
  const { data } = await api.post<LoginResponse>("/auth/login/", { email, password });
  setAuthToken(data.access);
  return { user: mapUser(data.user), token: data.access, refresh: data.refresh };
}

export async function register(payload: RegisterData): Promise<RegisterResponse> {
  const backendPayload = {
    email: payload.email,
    password: payload.password,
    password_confirm: payload.password,
    first_name: payload.firstName,
    last_name: payload.lastName,
    phone: `${payload.phonePrefix}${payload.phone}`,
    company: payload.companyName ?? "",
    role: "client",
  };
  const { data } = await api.post<RegisterResponse>("/auth/register/", backendPayload);
  return data;
}

export async function logout(): Promise<void> {
  try {
    await api.post("/auth/logout/", {});
  } finally {
    setAuthToken(null);
  }
}

export async function me(): Promise<User> {
  const { data } = await api.get<BackendUser>("/auth/me/");
  return mapUser(data);
}
