import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";

const docs: Array<{ id: string; name: string; client: string; date: string; category: string }> = [];

export default function FournisseurDocuments() {
  const [query, setQuery] = useState("");
  return (
    <div className="space-y-4">
      <Card>
        <CardContent className="flex flex-wrap items-center justify-between gap-3 p-4">
          <Input className="max-w-md" value={query} onChange={(event) => setQuery(event.target.value)} placeholder="Rechercher un document..." />
          <Button className="bg-cyan text-white hover:bg-cyan/90">Uploader un document</Button>
        </CardContent>
      </Card>

      <Card>
        <CardHeader><CardTitle>Documents</CardTitle></CardHeader>
        <CardContent className="space-y-2">
          {docs
            .filter((doc) => doc.name.toLowerCase().includes(query.toLowerCase()) || doc.client.toLowerCase().includes(query.toLowerCase()))
            .map((doc) => (
              <div key={doc.id} className="flex flex-wrap items-center justify-between gap-2 rounded-lg border border-slate-200 p-3 text-sm">
                <div>
                  <p className="font-medium">{doc.name}</p>
                  <p className="text-xs text-slate-500">{doc.client} - {doc.category} - {doc.date}</p>
                </div>
                <div className="flex gap-2">
                  <Button size="sm" variant="outline">Previsualiser</Button>
                  <Button size="sm" variant="outline">Partager</Button>
                  <Button size="sm" variant="outline">Telecharger</Button>
                </div>
              </div>
            ))}
        </CardContent>
      </Card>
    </div>
  );
}
