import { useState } from "react";
import { ChevronLeft, ChevronRight, Plus } from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";

type CalendarEvent = { id: string; time: string; client: string; domain: string; status: string };
const events: CalendarEvent[] = [];

const statusColor: Record<string, string> = {
  Confirme: "bg-cyan-100 border-cyan-300 text-cyan-800",
  "En attente": "bg-amber-100 border-amber-300 text-amber-800",
  Annule: "bg-slate-200 border-slate-300 text-slate-700",
};

export default function FournisseurCalendar() {
  const [view, setView] = useState<"Semaine" | "Jour" | "Mois">("Semaine");
  const [selected, setSelected] = useState<CalendarEvent | null>(null);
  const [availability, setAvailability] = useState({
    monday: "09:00-18:00",
    tuesday: "09:00-18:00",
    wednesday: "09:00-18:00",
    thursday: "09:00-18:00",
    friday: "09:00-17:00",
    blockSlot: "",
  });

  return (
    <div className="grid gap-4 xl:grid-cols-12">
      <div className="space-y-4 xl:col-span-9">
        <Card>
          <CardContent className="flex flex-wrap items-center justify-between gap-3 p-4">
            <div className="flex gap-2">
              {(["Semaine", "Jour", "Mois"] as const).map((item) => (
                <Button key={item} variant={view === item ? "default" : "outline"} className={view === item ? "bg-cyan text-white hover:bg-cyan/90" : ""} onClick={() => setView(item)}>
                  {item}
                </Button>
              ))}
            </div>
            <div className="flex items-center gap-2">
              <Button size="icon" variant="outline"><ChevronLeft className="h-4 w-4" /></Button>
              <span className="text-sm font-medium">Semaine du 31 Mars</span>
              <Button size="icon" variant="outline"><ChevronRight className="h-4 w-4" /></Button>
            </div>
            <div className="flex items-center gap-2">
              <select className="h-10 rounded-md border border-slate-200 px-3 text-sm">
                <option>Tous experts</option>
                <option>Me. Salma</option>
                <option>Me. Youssef</option>
              </select>
              <Button className="bg-cyan text-white hover:bg-cyan/90"><Plus className="mr-1.5 h-4 w-4" />Nouvelle consultation +</Button>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader><CardTitle>Planning ({view})</CardTitle></CardHeader>
          <CardContent className="space-y-3">
            {events.map((event) => (
              <button
                key={event.id}
                className={`w-full rounded-lg border p-3 text-left ${statusColor[event.status]}`}
                onClick={() => setSelected(event)}
              >
                <p className="text-sm font-semibold">{event.time} - {event.client}</p>
                <p className="text-xs">{event.domain} - {event.status}</p>
                <p className="mt-1 text-xs opacity-75">Glisser pour reprogrammer</p>
              </button>
            ))}
          </CardContent>
        </Card>
      </div>

      <div className="space-y-4 xl:col-span-3">
        <Card>
          <CardHeader><CardTitle>Aujourd'hui</CardTitle></CardHeader>
          <CardContent className="space-y-2 text-sm">
            {events.map((event) => (
              <div key={`agenda-${event.id}`} className="rounded-md border border-slate-200 p-2">
                <p className="font-medium">{event.time} - {event.client}</p>
                <p className="text-xs text-slate-500">{event.domain}</p>
              </div>
            ))}
          </CardContent>
        </Card>

        <Card>
          <CardHeader><CardTitle>Disponibilites</CardTitle></CardHeader>
          <CardContent className="space-y-2 text-sm">
            <input className="h-10 w-full rounded-md border border-slate-200 px-3" value={availability.monday} onChange={(event) => setAvailability((prev) => ({ ...prev, monday: event.target.value }))} />
            <input className="h-10 w-full rounded-md border border-slate-200 px-3" value={availability.tuesday} onChange={(event) => setAvailability((prev) => ({ ...prev, tuesday: event.target.value }))} />
            <input className="h-10 w-full rounded-md border border-slate-200 px-3" value={availability.wednesday} onChange={(event) => setAvailability((prev) => ({ ...prev, wednesday: event.target.value }))} />
            <input className="h-10 w-full rounded-md border border-slate-200 px-3" value={availability.thursday} onChange={(event) => setAvailability((prev) => ({ ...prev, thursday: event.target.value }))} />
            <input className="h-10 w-full rounded-md border border-slate-200 px-3" value={availability.friday} onChange={(event) => setAvailability((prev) => ({ ...prev, friday: event.target.value }))} />
            <input className="h-10 w-full rounded-md border border-slate-200 px-3" placeholder="Bloquer un creneau (ex: 12:00-13:30)" value={availability.blockSlot} onChange={(event) => setAvailability((prev) => ({ ...prev, blockSlot: event.target.value }))} />
            <Button
              className="w-full bg-cyan text-white hover:bg-cyan/90"
              onClick={async () => {
                await fetch("/api/experts/me/availability", {
                  method: "PATCH",
                  headers: { "Content-Type": "application/json" },
                  body: JSON.stringify(availability),
                }).catch(() => undefined);
              }}
            >
              Enregistrer disponibilites
            </Button>
          </CardContent>
        </Card>
      </div>

      {selected && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 p-4">
          <Card className="w-full max-w-lg">
            <CardHeader>
              <CardTitle>Details consultation</CardTitle>
            </CardHeader>
            <CardContent className="space-y-2 text-sm">
              <p>Client: {selected.client}</p>
              <p>Domaine: {selected.domain}</p>
              <p>Horaire: {selected.time}</p>
              <p>Statut: {selected.status}</p>
              <div className="flex justify-end">
                <Button variant="outline" onClick={() => setSelected(null)}>Fermer</Button>
              </div>
            </CardContent>
          </Card>
        </div>
      )}
    </div>
  );
}
