import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";

const reportBlocks: Array<{ label: string; value: string }> = [];

export default function FournisseurReports() {
  return (
    <div className="space-y-4">
      <Card>
        <CardHeader className="flex-row items-center justify-between">
          <CardTitle>Rapports</CardTitle>
          <div className="flex gap-2">
            <Button variant="outline">Exporter PDF</Button>
            <Button className="bg-cyan text-white hover:bg-cyan/90">Exporter CSV</Button>
          </div>
        </CardHeader>
        <CardContent className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
          {reportBlocks.map((block) => (
            <div key={block.label} className="rounded-lg border border-slate-200 p-4">
              <p className="text-sm text-slate-500">{block.label}</p>
              <p className="mt-1 text-xl font-semibold">{block.value}</p>
            </div>
          ))}
        </CardContent>
      </Card>

      <Card>
        <CardHeader><CardTitle>Analyse qualitative</CardTitle></CardHeader>
        <CardContent className="space-y-2 text-sm text-slate-700">
          <p>- Hausse continue des dossiers IA (+24% sur 6 mois).</p>
          <p>- Delais de traitement meilleurs sur RGPD grace aux playbooks.</p>
          <p>- Point de vigilance: factures impayees &gt; 30j sur segment startups.</p>
        </CardContent>
      </Card>
    </div>
  );
}
