import { useMemo, useState } from "react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { useDashboard } from "@/pages/client/DashboardContext";
import type { Consultation, ConsultationStatus } from "@/types/client";

const consultationStatusLabel = {
  planifiee: "Planifiee",
  en_cours: "En cours",
  terminee: "Terminee",
  annulee: "Annulee",
} as const;

export default function ClientConsultations() {
  const { consultations: initialConsultations } = useDashboard();
  const [consultations, setConsultations] = useState<Consultation[]>(initialConsultations);
  const [statusFilter, setStatusFilter] = useState<string>("tous");
  const [activeTab, setActiveTab] = useState<"avenir" | "passees">("avenir");

  const filtered = useMemo(() => {
    const now = Date.now();
    return consultations.filter((consultation) => {
      const isPast = new Date(consultation.scheduledAt).getTime() < now || consultation.status === "terminee";
      const tabMatch = activeTab === "avenir" ? !isPast : isPast;
      const statusMatch = statusFilter === "tous" || consultation.status === statusFilter;
      return tabMatch && statusMatch;
    });
  }, [consultations, activeTab, statusFilter]);

  const getCountdown = (isoDate: string) => {
    const delta = new Date(isoDate).getTime() - Date.now();
    const canJoin = delta <= 15 * 60 * 1000 && delta > -60 * 60 * 1000;
    const hours = Math.max(0, Math.floor(delta / 3600000));
    const mins = Math.max(0, Math.floor((delta % 3600000) / 60000));
    return { canJoin, text: `Dans ${hours}h ${mins}min` };
  };

  return (
    <Card>
      <CardHeader className="flex flex-row flex-wrap items-center justify-between gap-3">
        <CardTitle className="text-xl">Mes consultations</CardTitle>
        <select
          className="h-10 rounded-md border border-slate-200 bg-white px-3 text-sm dark:border-slate-700 dark:bg-slate-900"
          value={statusFilter}
          onChange={(event) => setStatusFilter(event.target.value)}
        >
          <option value="tous">Tous statuts</option>
          {Object.entries(consultationStatusLabel).map(([value, label]) => (
            <option key={value} value={value}>
              {label}
            </option>
          ))}
        </select>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="flex gap-2">
          <Button variant={activeTab === "avenir" ? "default" : "outline"} onClick={() => setActiveTab("avenir")}>
            A venir
          </Button>
          <Button variant={activeTab === "passees" ? "default" : "outline"} onClick={() => setActiveTab("passees")}>
            Passees
          </Button>
        </div>
        <div className="grid gap-4 md:grid-cols-2">
          {filtered.map((consultation) => {
            const join = getCountdown(consultation.scheduledAt);
            return (
              <Card key={consultation.id} className="rounded-xl border border-slate-200 p-4 dark:border-slate-700">
                <div className="flex items-start gap-3">
                  <div className="flex h-10 w-10 items-center justify-center rounded-full bg-cyan/15 text-cyan">
                    {consultation.expert.firstName[0]}
                  </div>
                  <div className="flex-1">
                    <p className="font-semibold">
                      Me. {consultation.expert.lastName}
                    </p>
                    <p className="text-sm text-slate-600 dark:text-slate-300">Specialite: {consultation.expert.specialization[0].replace("_", " ")}</p>
                  </div>
                </div>
                <p className="mt-3 text-sm text-slate-600 dark:text-slate-300">
                  📅 {new Date(consultation.scheduledAt).toLocaleString("fr-FR", { weekday: "long", day: "2-digit", month: "short", hour: "2-digit", minute: "2-digit" })} ({consultation.duration} min)
                </p>
                <p className="mt-1 text-sm text-slate-600 dark:text-slate-300">🔗 Consultation visio</p>
                <Badge className="mt-2 bg-amber-100 text-amber-700">{consultationStatusLabel[consultation.status as ConsultationStatus]}</Badge>

                {activeTab === "avenir" ? (
                  <div className="mt-4 flex flex-wrap items-center gap-2">
                    <Button
                      size="sm"
                      className="bg-cyan text-white hover:bg-cyan/90 disabled:bg-slate-300"
                      disabled={!join.canJoin}
                      onClick={() => consultation.meetingUrl && window.open(consultation.meetingUrl, "_blank", "noopener,noreferrer")}
                    >
                      Rejoindre
                    </Button>
                    <Button size="sm" variant="outline">
                      Reprogrammer
                    </Button>
                    <Button size="sm" variant="outline" className="border-red-200 text-red-600 hover:bg-red-50">
                      Annuler
                    </Button>
                    {!join.canJoin && <span className="text-xs text-slate-500">{join.text}</span>}
                  </div>
                ) : (
                  <div className="mt-4 space-y-3">
                    <details className="rounded-md border border-slate-200 p-3 text-sm dark:border-slate-700">
                      <summary className="cursor-pointer font-medium">Compte-rendu de consultation</summary>
                      <p className="mt-2 text-slate-600 dark:text-slate-300">{consultation.report || "Aucun compte-rendu disponible."}</p>
                    </details>
                    {!consultation.notes && (
                      <div className="flex gap-1">
                        {[1, 2, 3, 4, 5].map((star) => (
                          <button
                            key={star}
                            type="button"
                            onClick={() =>
                              setConsultations((prev) =>
                                prev.map((item) => (item.id === consultation.id ? { ...item, notes: `Note: ${star}/5` } : item))
                              )
                            }
                            className="text-lg text-amber-500"
                          >
                            ☆
                          </button>
                        ))}
                      </div>
                    )}
                    <Button size="sm" variant="outline">
                      Telecharger le rapport
                    </Button>
                  </div>
                )}
              </Card>
            );
          })}
          {filtered.length === 0 && (
            <div className="rounded-xl border border-dashed border-slate-300 p-6 text-sm text-slate-500 dark:border-slate-700">
              Aucune consultation pour ce filtre.
            </div>
          )}
        </div>
      </CardContent>
    </Card>
  );
}
